<template>
    <div>
      <el-card>
        <el-form label-width="100px" size="mini">
            <el-form-item label="取款金额(元)">
            <el-input type="number" v-model="account"></el-input>
            </el-form-item>
        </el-form>
        <el-form label-width="80px" size="mini">
            <div style="text-align: center;">
                <el-button type="primary" @click="submit">提交</el-button>
            </div>
        </el-form>
      </el-card>

      <el-card v-if="info['余额']">
        <p>操作：{{info['操作']}}</p>
        <p>卡号：{{info['卡号']}}</p>
        <p>余额：{{info['余额']}}元</p>
        
      </el-card>
        
    </div>
  </template>
  
  <script>
    import {
      userfunWithdrawals, // 取款
  } from '@/api/index'
  
    export default {
      data() {
        return {
            account: 0,
            info: {}
        }
      },
      mounted(){

      },
      methods: {
        // 取款
        async submit(){
            let page = {
                account: this.account
            }
            if(!page.account){
                this.$message.warning('请输入取款金额')
                return
            }
            let res = await userfunWithdrawals(page)
            if(res['余额']){
                this.info = res
            }else {
                this.$message.error(res)
            }
        },
      }
    }
  </script>
  
  <style scoped>

    /deep/.el-card{
      margin-top: 10px;
    }
  </style>
  
  


